mapper.select:
/* sc_CmmnCdDao_getCmmnCd */ SELECT A.CL_CD, A.CL_CD_NM, B.CMMN_CD, B.CMMN_CD_NM, B.CMMN_CD_DC FROM tc_wri_cl_cd A, tc_wri_cd B WHERE A.CL_CD = B.CL_CD AND A.USE_YN = 'Y' AND B.USE_YN = #{useYn}
AND A.CL_CD = #{clCd}
AND B.CMMN_CD_NM LIKE #{cmmnCdNm} || '%'
AND B.USR_DFN_ETC1 LIKE #{usrDfnEtcVal} || '%'
AND B.USR_DFN_ETC2 LIKE #{usrDfnEtcVal} || '%'
AND B.USR_DFN_ETC3 LIKE #{usrDfnEtcVal} || '%'
ORDER BY A.CL_CD, B.SORT_ORDR, B.CMMN_CD

/* sc_CmmnCdDao_getMenuList */ SELECT LEVEL, A.MENU_SYS_SE_CD, A.MENU_ID, A.MENU_NM, A.MENU_ORDR, A.MENU_LEVEL FROM tn_wri_dmst_menu A WHERE A.MENU_SYS_SE_CD = #{menuSysSeCd}
AND (A.MENU_LEVEL = '1' OR A.MENU_NM LIKE #{menuNm} || '%')
CONNECT BY NOCYCLE PRIOR A.MENU_ID = A.UPPER_MENU_ID
START WITH A.MENU_ID = #{menuId}
START WITH A.MENU_LEVEL = '1'
ORDER SIBLINGS BY A.MENU_ORDR

/* sc_CmmnCdDao_getScrinSearch */ SELECT A.SCRIN_ID, A.DMST_SYS_SE_CD, A.SCRIN_NM, A.SCRIN_URL, A.SCRIN_DC, A.SAP_LCNS_TY_CD, A.USE_YN FROM tn_wri_dmst_scrin A WHERE 1=1
AND A.DMST_SYS_SE_CD = #{dmstSysSeCd}
AND A.SCRIN_NM LIKE #{scrinNm} || '%'
AND A.USE_YN = #{useYn}
ORDER BY DMST_SYS_SE_CD, SCRIN_ID, SCRIN_NM
